@ARTICLE{10.1017/s0040298223000086,
	author = {Shley-Zondiner, S.},
	title = {STRIVING FOR THE UNDERNEATH: BODY AND PATHOS IN CHAYA CZERNOWIN’S COMPOSITION FOR VOICE IN INFINITE NOW AND HEART CHAMBER},
	journal = {Tempo (United Kingdom)},
	year = {2023},
	abstract = {In her two recent operas, Heart Chamber (2017–19) and Infinite Now (2015–16), Chaya Czernowin uses vocal ensembles to embody a single character. In a 2016 article, she explained that she wanted to liberate the individual voice from its fixed emotional, social and individual conventions (especially its ingrained pathos), and to work with the voice as a free imaginative sonic material, using the ensemble technique to achieve this. This article argues that the voice ensemble technique amplifies and intensifies the pathos of the voice rather than eliminating it. Recognising that the voice has strong somatic qualities since it is produced in the body, I suggest a material-musical analysis, based on the theories of Hans Ulrich Gumbrecht and Brian Massumi, that focuses on the body, the sensual experience and the physical space, and rejects the hermeneutic tradition that refers to meaning and interpretation only. What emerges is that the voices, instrumentation and electronics of the ensemble are designed to embody the inner body and the outer space at the same time. The voice ensemble may split and produce multi-layered mental–physical states, and express how traditional dichotomies, such as culture/nature, body/mind and subject/object, can meld into multi-perspective processual movements. It is in this intersection of sound and drama, manifesting the corporeal, that the unique power of opera is evinced. © The Author(s), 2023. Published by Cambridge University Press. ER -},
	doi = {10.1017/s0040298223000086},
	type = {JOUR}
}

@ARTICLE{10.1007/s10548-025-01134-x,
	author = {Kleber, B. and Dale, C. and Zamorano, A.M. and Lotze, M. and Luders, E. and Kurth, F.},
	title = {Increased Callosal Thickness in Early Trained Opera Singers},
	journal = {Brain Topography},
	year = {2025},
	abstract = {Structural adaptations of the corpus callosum have been well documented in early-trained instrumental musicians, reflecting experience-dependent plasticity in response to bimanual coordination and auditory–motor integration. Although the sensorimotor demands of singing differ, professional vocal training also requires precise control of bilateral vocal tract musculature and integration of auditory feedback; yet, less is known about whether similar adaptations occur in professional singers. This study used structural neuroimaging to investigate variations in callosal thickness in relation to vocal training in 55 participants, including 27 professionally trained opera singers and 28 non-singers. A significant negative correlation between age at first singing lesson and callosal thickness was observed in singers, with effects surviving correction for multiple comparisons in the anterior third (rostrum, genu, rostral body), at the anterior-posterior midbody border, and the isthmus. While group comparisons revealed greater callosal thickness in singers than non-singers in these same regions, these differences did not remain significant after correction. Likewise, a positive correlation between years of professional singing and callosal thickness in the midbody did not survive correction for multiple comparisons. Our main finding aligns with prior evidence of training-related plasticity in the corpus callosum and suggests that early musical experience—including in the context of intensive vocal practice—may contribute to enhanced interhemispheric connectivity. Although the current design does not allow us to isolate effects specific to singing compared to other forms of sensorimotor training, the results underscore developmental timing as a key factor in how prolonged musical experience may shape brain structure. © The Author(s) 2025. ER -},
	doi = {10.1007/s10548-025-01134-x},
	type = {JOUR}
}

@ARTICLE{10.1016/j.jvoice.2020.07.022,
	author = {Glasner, J.D. and Johnson, A.M.},
	title = {Effects of Historical Recording Technology on Vibrato in Modern-Day Opera Singers},
	journal = {Journal of Voice},
	year = {2022},
	abstract = {Objective: Past literature indicates that vibrato measurements of singers objectively changed (i.e., vibrato rate decreased and vibrato extent increased) from 1900 to the present day; however, historical audio recording technology may distort acoustic measurements of the voice output signal, including vibrato. As such, the listener's perception of historical singing may be influenced by the limitations of historical technology. This study attempts to show how the wax cylinder phonograph system—the oldest form of mass-produced audio recording technology—alters the recorded voice output signal of modern-day singers and, thus, provides an objective lens through which to study the effect(s) of historical audio recording technology on vibrato measurements. Methods: Twenty professional Western opera singers sang a messa di voce on the vowel [a] and on the pitch C4 for male singers and C5 for female singers, three times into a flat-response omnidirectional microphone and onto an Edison Home Phonograph simultaneously. The middle 1–3 seconds (6–10 vibrato cycles) of each sample was analyzed for vibrato rate, vibrato extent, jitter (ddp), shimmer (dda), and fundamental frequency for each recording condition (wax cylinder phonograph or microphone). Steady-state and frequency-modulating sinewave test signals were also recorded under the multiple recording conditions. Results: Results indicated no significant effect of recording condition on vibrato rate (mean [standard deviation], cylinder: 5.3 Hz [0.5], microphone: 5.3 Hz [0.5]) and no significant difference was found for mean fundamental frequency (cylinder: 389 Hz [137], microphone: 390 Hz [137]). A significant main effect of recording condition was found for vibrato extent (cylinder: ±103 cents [30], microphone: ±100 cents [31]). Additionally, mean jitter (ddp) (cylinder: 1.22% [1.09], microphone: 0.24% [0.12]) and mean shimmer (dda) (cylinder: 9.40% [4.90], microphone: 1.92% [0.94]) were significantly higher for the cylinder recording condition, indicating more cycle-to-cycle variability in the wax cylinder recorded signal. Analysis of test signals revealed similar patterns based on recording condition. Discussion: This study validates past scholarly inquiry about vibrato measurements as extracted from digitized wax cylinder phonograph recordings by demonstrating that measured vibrato rate remains constant during both recording conditions. In other words, vibrato rate as measured from historical recordings can be viewed as an accurate representation of the historical singer being studied. Furthermore, it suggests that the value of prior vibrato extent measurements from these acoustic recordings may be slightly overestimated from the original voice output signals produced by singers near the beginning of the 20th century (i.e., a narrow vibrato extent might have been numerically smaller on average). Increased jitter and shimmer in the wax cylinder recording conditions may be indicative of nonlinearities in the phonograph recording or playback systems © 2020 The Voice Foundation ER -},
	doi = {10.1016/j.jvoice.2020.07.022},
	type = {JOUR}
}

@ARTICLE{10.6244/jomr.202111_(35).04,
	author = {Zhang, X. and Fyr, K.},
	title = {The use of traditional chinese elements in selected saxophone works by Lei Liang},
	journal = {Journal of Music Research},
	year = {2021},
	abstract = {The purpose of this study is to examine the use of traditional Chinese elements in two of Lei Liang’s saxophone works, Peking Opera Soliloquy and Xiaoxiang, and to analyze how Liang incorporates such elements into compositions written largely with Western musical techniques and vocabularies. Traditional Chinese elements identified in these pieces include Peking Opera singing, Peking Opera accompaniment, traditional Chinese melodies, one-note polyphony, and other Chinese artistic elements such as negative space and calligraphy. This study also explores how the traditional Chinese musical and artistic elements are reproduced or alluded to with western musical notation, genres, saxophone performance styles and techniques in creative and innovative ways. It is hoped that this research can inspire further investigations on works of saxophone or works of other musical instruments with embedded Chinese elements. © 2021, National Taiwan Normal University-College of Music. All rights reserved. ER -},
	doi = {10.6244/jomr.202111_(35).04},
	type = {JOUR}
}

@ARTICLE{10.31893/multiscience.2026254,
	author = {Li, M. and Chantamala, O.},
	title = {Tradition and innovation in Henan Opera: An ethnographic study of Chen Suzhen's artistic legacy and the aesthetics of performance},
	journal = {Multidisciplinary Science Journal},
	year = {2026},
	abstract = {Henan Opera stands as one of China’s most prominent regional operatic traditions, renowned for its vivid vocal styles, heroic spirit, and symbolic stagecraft. The researcher conducted qualitative research and collected data through field investigations involving key informants. Research tools included observation and interviews. This review explores its performance aesthetics through the artistry of Chen Suzhen, whose legacy embodies both preservation and innovation. Chen mastered the four pillars of performance—singing, recitation, acting, and combat—yet distinguished herself by fusing these skills into psychologically rich and emotionally authentic portrayals. Her artistry was characterized by refined emotional expression, from subtle eye movements and powerful crying scenes to the seamless integration of emotion into her vocal resonance. Through mastery of head, chest, and oral resonance, she transformed singing into a vessel of character psychology. She also redefined the use of costumes and props, elevating water sleeves and fans into expressive tools that externalized inner feelings. These innovations established the Chen School, a stylistic lineage that continues to shape Henan Opera. Preserving its vitality requires combining individual and group transmission, archival protection, and new educational initiatives. Chen Suzhen’s ethos—anchoring technique in emotion and role psychology—offers a sustainable path for Henan Opera’s future, uniting tradition with contemporary relevance. Copyright (c) 2026 The Authors. This work is licensed under a Creative Commons Attribution-NonCommercial-NoDerivatives 4.0 International License. ER -},
	doi = {10.31893/multiscience.2026254},
	type = {JOUR}
}

@ARTICLE{10.1080/00016489.2022.2162961,
	author = {Szkiełkowska, A. and Krasnodębska, P. and Mitas, A. and Bugdol, M. and Bugdol, M. and Romaniszyn-Kania, P. and Pollak, A.},
	title = {Electrophysiological predictors of hyperfunctional dysphonia},
	journal = {Acta Oto-Laryngologica},
	year = {2023},
	abstract = {Background: The relation between the autonomic nervous system (ANS) and muscles of the vocal tract is of particular importance when considering the pathomechanism of a functional voice disorder. Aims: The aim of this study was to record electrophysiological indicators from the ANS as well as the tone of the external laryngeal muscle and test whether together they could point to an enhanced risk of primary functional voice disorder. Materials and methods: The study material consisted of 81 people, 27 of whom were professional opera singers. None reported any voice complaints. The research comprised ENT and phoniatric examination, superficial electromyography (SEMG), and recording of physiological indicators (pulse rate, skin resistance). Results: All subjects had a clear voice with no sign of vocal disability. Endoscopy revealed laryngeal hyperfunction in 26 people. SEMG revealed that the 26 had increased external laryngeal muscle tone during phonation, and this finding correlated with a change in certain electrophysiological indicators HRV, BVP, EDA. Conclusions: We conclude that anomalies in electrophysiological parameters in individuals with subclinical symptoms of functional voice disorder may be at risk of developing fully symptomatic hyperfunctional dysphonia in the future. Vocal training, which differentiates singers and non-singers, is known to have an effect on subclinical hyperfunctional dysphonia. Significance: By measuring indicators of hyperfunctional dysphonia, it may be possible to take remedial action before symptomatic dysphonia develops. © 2023 Acta Oto-Laryngologica AB (Ltd). ER -},
	doi = {10.1080/00016489.2022.2162961},
	type = {JOUR}
}

@ARTICLE{10.1177/00315125251407932,
	author = {Wang, N. and Cai, Z.},
	title = {Processing of Vocal Music Using Artificial Intelligence: Unveiling Creative Potential and Shaping Listener Perception},
	journal = {Perceptual and Motor Skills},
	year = {2025},
	abstract = {Technological transformations occurring at the intersection of artificial intelligence and vocal music necessitate an epistemological reevaluation of both perceptual mechanisms and creative capacities. The integration of artificial intelligence with vocal music compels a reconsideration of perceptual mechanisms and creative potential. While prior research has focused primarily on the technical accuracy of AI systems, their influence on perception and broader cultural implications has remained largely unexplored. The present study addresses this research gap. This study quantitatively assesses the impact of AI on vocal-music processing. Employing a mixed-methods approach, it examines algorithmic integration within musical traditions, explores correlations between technical parameters and affective responses that characterize human–AI collaboration, and compares architectural variations among systems along with their perceptual consequences. Statistical analysis revealed differences in genre receptivity: contemporary music (EDM and jazz) received a mean score of μ = 9.0, whereas traditional genres such as opera (μ = 5.0) and classical music (μ = 6.0) remained at comparatively low levels. The integration of artificial intelligence enhanced musicians’ creative output from M = 6.7 to M = 8.1 and increased audience engagement by 12%. Correlational analysis confirmed a strong association between emotional intensity and listener engagement (r = 0.72). Educational institutions may implement AI-enhanced vocal training programs; recording studios are adopting system-specific technologies tailored to desired affective outcomes; and cultural-heritage initiatives can leverage algorithmic assistance while preserving interpretive authenticity. © The Author(s) 2025 ER -},
	doi = {10.1177/00315125251407932},
	type = {JOUR}
}

@ARTICLE{10.1016/j.jvoice.2021.08.008,
	author = {Melton, J. and Bradford, Z. and Lee, J.},
	title = {Speak Like You Sing: Integrating Classical Techniques From Theatre and Music in Spoken Dialogue for Opera},
	journal = {Journal of Voice},
	year = {2024},
	abstract = {Objective: In order to maintain characterization throughout a production, opera singers frequently need skills in more than one vocal task. This exploratory study investigated spoken dialogue before and after two hours of training (one-hour class, one-hour tutorial) in the use of language as an actor, with breath management, pitch range, and resonance strategies of a singer. Comparative recordings of sung and spoken material were analyzed for acoustic qualities. Design: At the National Opera Center, New York, six professional singers from different voice categories recorded one minute of spoken dialogue before training. Approximately a week later, they recorded one minute of an aria, unaccompanied, followed by the spoken dialogue post-training, then improvised a one - two-minute performance moving between singing and speaking. Data were analyzed for fundamental frequency (F0), sound pressure level (SPL), and long-term average spectrum (LTAS). Results: Comparing for all singers pre- to post-training, mean F0 of spoken dialogue increased and SPL mean and range increased. Comparing aria to spoken dialogue post-training, SPL range increased. F0 ranges were closer to each other in improvisation than in separate performances of aria and dialogue. Energy peaks between 2 and 4 kHz on LTAS appeared in more than one performing condition. Conclusions: In spoken dialogue post-training, some F0 and SPL data gravitated toward those of the aria and away from the initial recording, suggesting that participants were beginning to transfer production skills from singing to speaking. A perceptual study is needed to assess characterization and the use of language pre- and post-training. © 2021 The Authors ER -},
	doi = {10.1016/j.jvoice.2021.08.008},
	type = {JOUR}
}

@ARTICLE{10.1525/jams.2023.76.2.279,
	author = {Zohn, S.},
	title = {Remember Me: Vocal Cadenzas as Mementos in Nineteenth-Century Musical Autograph Albums},
	journal = {Journal of the American Musicological Society},
	year = {2023},
	abstract = {Between the 1830s and the 1880s, leading female singers such as Henriette Rossi Sontag, Laure Cinti-Damoreau, Adelina Patti, and Pauline Viardot participated in a widespread custom of inscribing original vocal cadenzas in autograph albums (also known as friendship albums, keepsake albums, alba amicorum, or Stammbücher). The appeal of album cadenzas, along with other compact inscriptions, reflects a wider Romantic fascination with remembering through small keepsakes such as miniature almanacs and annual compilations of poetry, prose, or music. Whether improvised in the presence of collectors or offered as souvenirs of earlier performances, cadenzas functioned as mementos of musical and social encounters while visually representing singers’ musical personae through performative gestures. These florid pieces also allowed female singers to exercise agency as both creative artists and curators of their public images, much like the (mostly male) composers whose musical signatures fill surrounding album leaves. As performance-practical sources, vocal cadenzas preserve rare and revealing traces of singers’ artistry; many, in fact, can be linked to specific concerts or performances of operas by Bellini, Donizetti, Meyerbeer, Rossini, Verdi, and others. In the case of Cinti-Damoreau, such music illuminates the connection between improvisation, performance, and pedagogy. The gradual disappearance of album cadenzas during the last quarter of the nineteenth century is attributable not only to a waning interest in musical improvisation generally, but also to a shift in creative authority away from singers and toward composers, particularly in the operatic realm. © 2023 University of California Press. All rights reserved. ER -},
	doi = {10.1525/jams.2023.76.2.279},
	type = {JOUR}
}

@ARTICLE{10.3389/fcomp.2024.1187933,
	author = {Merendino, N. and Rodà, A. and Masu, R.},
	title = {“Below 58 BPM,” involving real-time monitoring and self-medication practices in music performance through IoT technology},
	journal = {Frontiers in Computer Science},
	year = {2024},
	abstract = {The project presented in this paper illustrates the design process for the development of an IoT system that monitors a specific bio-metric parameter (heart rate) in real time and provides feedback for an opera singer, as well as adding effects that manipulate the sounds emitted by the body during a self-healing practice. This allows the singer to rest and alternate opera singing techniques (which is very demanding) with other less demanding singing techniques and even a self-healing session in case of necessity during a performance. The case study presented in this paper has been developed with and for Eleonora Amianto, an opera singer who suffered from a carotid aneurysm. We performed an idiographic design process, closely collaborating with Eleonora, and developed a wearable IoT that suited her health and artistic needs. In the design of the system, we explore the intersection between self-healthcare and performative arts, focusing on the use of an Internet of Musical Things (IoMusT) system to implement medical prevention and treatment practices in an art performance. The system is developed using open-source tools, allowing for easy replication and improvement, as well as reducing risks of obsolescence and costs of updating. We complement a formal evaluation session with field notes collected during the design phase. We could observe a positive effect of the system on Eleonora's practice and its potential applications within different performative scenarios. Copyright © 2024 Merendino, Rodà and Masu. ER -},
	doi = {10.3389/fcomp.2024.1187933},
	type = {JOUR}
}
